503→## Query Optimization
504→
505→### Use Indexes
506→
507→```typescript
508→// In migration
509→table.index(['field1', 'field2', 'deleted_at']);
510→table.index(['foreign_key', 'status', 'deleted_at']);
511→```
512→
513→### Select Specific Fields
514→
515→```typescript
516→// ❌ Bad - selects all fields
517→const data = await this.knexRead('table').where({ id });
518→
519→// ✅ Good - only needed fields
520→const data = await this.knexRead('table')
521→  .select('id', 'name', 'email')
522→  .where({ id });
523→```
524→
525→### Use Pagination
526→
527→```typescript
528→async findPaginated({
529→  limit = 10,
530→  offset = 0,
531→}: {
532→  limit?: number;
533→  offset?: number;
534→}): Promise<IEntityBase[]> {
535→  return this.knexRead<BaseEntityDto>(this.tableName)
536→    .whereNull('deleted_at')
537→    .limit(limit)
538→    .offset(offset)
539→    .orderBy('created_at', 'desc');
540→}
541→```
542→
543→### Efficient Joins
544→
545→```typescript
546→const data = await this.knexRead('users as u')
547→  .join('orders as o', 'u.id', 'o.user_id')
548→  .select('u.id', 'u.name', 'o.total')
549→  .where('u.deleted_at', null)
550→  .where('o.deleted_at', null);
551→```
552→
553→### Use Transactions for Multiple Writes
554→
555→```typescript
556→async createWithRelations({ data }: { data: Data }): Promise<Result> {
557→  return this.knexWrite.transaction(async (trx) => {
558→    const entity = await trx('entities').insert(data).returning('*');
559→
560→    await trx('relations').insert({
561→      entity_id: entity[0].id,
562→      related_data: data.related,
563→    });
564→
565→    return entity[0];
566→  });
567→}
568→```
569→
570→### Batch Operations
571→
572→```typescript
573→async createBatch({ items }: { items: IEntityCreate[] }): Promise<void> {
574→  const batchSize = 100;
575→
576→  for (let i = 0; i < items.length; i += batchSize) {
577→    const batch = items.slice(i, i + batchSize);
578→
579→    await this.knexWrite.transaction(async (trx) => {
580→      const insertData = batch.map((item) => ({
581→        _id: randomUUID(),
582→        ...item,
583→      }));
584→
585→      await trx(this.tableName).insert(insertData);
586→    });
587→  }
588→
589→  this.logger.log(`Inserted ${items.length} records in batches`);
590→}
591→```
592→
593→## Common Query Patterns
594→
595→### Find with Conditions
596→
597→```typescript
598→async findByConditions({
599→  status,
600→  categoryId,
601→}: {
602→  status: string;
603→  categoryId?: number;
604→}): Promise<IEntityBase[]> {
605→  const query = this.knexRead<BaseEntityDto>(this.tableName)
606→    .where({ status })
607→    .whereNull('deleted_at');
608→
609→  if (categoryId) {
610→    query.where({ category_id: categoryId });
611→  }
612→
613→  return query;
614→}
615→```
616→
617→### Count Records
618→
619→```typescript
620→async count(): Promise<number> {
621→  const result = await this.knexRead(this.tableName)
622→    .whereNull('deleted_at')
623→    .count('* as count')
624→    .first();
625→
626→  return result ? Number(result.count) : 0;
627→}
628→```
629→
630→### Check Existence
631→
632→```typescript
633→async exists({ entityId }: { entityId: number }): Promise<boolean> {
634→  const result = await this.knexRead(this.tableName)
635→    .where({ entity_id: entityId })
636→    .whereNull('deleted_at')
637→    .first();
638→
639→  return !!result;
640→}
641→```
642→
643→### Aggregate Queries
644→
645→```typescript
646→async getStatistics(): Promise<Statistics> {
647→  const result = await this.knexRead(this.tableName)
648→    .whereNull('deleted_at')
649→    .select(
650→      this.knexRead.raw('COUNT(*) as total'),
651→      this.knexRead.raw('AVG(count) as average'),
652→      this.knexRead.raw('MAX(count) as maximum')
653→    )
654→    .first();
655→
656→  return {
657→    total: Number(result.total),
658→    average: Number(result.average),
659→    maximum: Number(result.maximum),
660→  };
661→}
662→```
663→
664→## Read/Write Connection Pattern
665→
666→**Critical:** Always use correct connection for operation type.
667→
668→```typescript
669→// ✅ Read operations - use knexRead
670→async getData(): Promise<Data[]> {
671→  return this.knexRead('table')
672→    .whereNull('deleted_at')
673→    .select('*');
674→}
675→
676→// ✅ Write operations - use knexWrite
677→async createData(data: CreateDto): Promise<Data> {
678→  return this.knexWrite.transaction(async (trx) => {
679→    const [result] = await trx('table').insert(data).returning('*');
680→    return result;
681→  });
682→}
683→
684→// ✅ Update operations - use knexWrite
685→async updateData(id: string, data: UpdateDto): Promise<Data> {
686→  return this.knexWrite.transaction(async (trx) => {
687→    await trx('table').where({ _id: id }).update(data);
688→    return trx('table').where({ _id: id }).first();
689→  });
690→}
691→```
